var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"어… 저, 저기 좀 보세요.","JPN":"あ……あ、あれを見て。","ENG":"Um... Look over there.","TWN":"呃……快、快看那邊。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"침식체들이 순식간에…….","JPN":"侵食体があっという間に……","ENG":"The C.O.s just vanished in an instant...","TWN":"侵蝕體們一下子……"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"흔적도 없이 증발했어?","JPN":"跡形もなく消えた？","ENG":"They're gone without a trace?","TWN":"連痕跡都蒸發了？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"아무래도 우리 지원 요청을 들은 자들이 엄청난 놈들인가 보군.","JPN":"どうやら俺たちの支援要請に応えてくれたのは、とんでもないやつらだったようだな。","ENG":"Whoever heard our call for help must be top tier.","TWN":"看來支援我們的傢伙們是超級狠角色啊。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"다들, 서두르자고.","JPN":"皆、急ぐぞ。","ENG":"Let's move.","TWN":"大家動作快。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"지금은 조용하더라도, 언제 다시 놈들이 쳐들어올지 모르니까.","JPN":"今は落ち着いていても、またいつやつらが襲ってくるか分からない。","ENG":"It's quiet now, but they could come back any time.","TWN":"現在雖然很平靜靜，但不知道什麼時候又會再進攻。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"저… 감사합니다.","JPN":"あの……ありがとうございます。","ENG":"Th-thank you.","TWN":"那個……謝謝各位。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"소속과 성함을 알려주시면 관리국에 보고해 꼭 보답하겠습니다.","JPN":"所属とお名前をお聞きしてもよろしいでしょうか。管理局に報告し、必ず恩返しします。","ENG":"Tell me your affiliation and name. I'll report it to the Administration and make sure you're rewarded.","TWN":"如果能告訴我所屬和姓名，我會向管理局報告，報答各位的恩情。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"이 와중에도 공치사를 논하려는 거야? 직업 정신이 투철하네.","JPN":"こんな状況でそれを聞くの？　真面目ね。","ENG":"Even now, you’re trying to take credit? That's some professional dedication","TWN":"這種情況還在討論功勞？真是可怕的職業病。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"흠~ 보수 같은 건 필요 없는데 말이지.","JPN":"う～ん、別に報酬はいらないのよね。","ENG":"Hm... I don't need payment, though.","TWN":"哼～我是不需要什麼報酬啦。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"용감한 후배님이 목숨까지 걸고 나섰는데 어떻게 보수를 바라고 움직이겠어?","JPN":"勇敢な後輩くんが命までかけて戦おうとしているのに、報酬目当てで動いたりしないわ。","ENG":"How could I ask for money when a brave junior like yourself risked his life?","TWN":"後輩這麼勇敢、連命都賭上了，我怎麼能為了報酬才行動呢？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"후…배님이요?","JPN":"後輩……ですか？","ENG":"J-junior?","TWN":"後、後輩……？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"난 코핀 컴퍼니 소속, 알렉스라고해.","JPN":"私はコフィンカンパニー所属、アレックスよ。","ENG":"I'm Alex with Coffin Company.","TWN":"我隸屬科芬公司，名叫雅蕾克絲。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"그리고 도시에서 침식체를 정리하고 있는 애들은 예고르, 빅터, 예프넨 그리고…….","JPN":"都市で侵食体を片付けている子たちはイェゴール、ヴィクター、イェフネン、そして……","ENG":"And the ones sweeping the city are Yegor, Viktor, Yevnen, and...","TWN":"還有在城裡清理侵蝕體的那些人分別是伊高爾、維克多、耶芙涅，還有……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"이렇게 하나하나 얘기하다 보면 끝이 없으려나?","JPN":"いちいち名前をあげてたらきりがないわね。","ENG":"If I list them one by one, we'll be here all day.","TWN":"這樣一個個介紹下去大概沒完沒了吧？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"당신이 이 도시의 총지휘관이야?","JPN":"あなたがこの都市の総指揮官？","ENG":"Are you the acting commander here?","TWN":"你是這座城市的總指揮官嗎？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"지금은… 그렇습니다.","JPN":"今は……そうです。","ENG":"For now... yes.","TWN":"現在……是這樣沒錯。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"저 4종 침식체 녀석이 부상하는 바람에 제 윗사람들은 전부 죽었거든요.","JPN":"あの第4種侵食体が浮上したせいで、私の上司は全員死亡しましたので。","ENG":"That Category 4 C.O. emerged and killed all my superiors.","TWN":"4級侵蝕體浮上來後，我的上司全死了。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"……정말 유감이네.","JPN":"……残念だったわね。","ENG":"...That's unfortunate.","TWN":"……真令人遺憾。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"최대한 빨리 온다고 온 건데 이렇게 됐을 줄은…….","JPN":"急いだつもりだったけど、こんなことになっていたなんて……","ENG":"We came as fast as we could, but I didn't expect this...","TWN":"我們已經盡快趕來了，沒想到會變成這樣……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"아닙니다.","JPN":"いいえ。","ENG":"No.","TWN":"不，沒那回事。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"여러분 덕분에 아직 대피하지 못한 사람들이 살아남을 수 있었습니다.","JPN":"皆さんのおかげで、避難できずにいた人々の命が助かりました。","ENG":"Thanks to you, people who hadn't evacuated yet survived.","TWN":"多虧各位，還沒撤離的人才能活下來。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"감사 인사는 저희가… 응?","JPN":"逆にお礼を……うん？","ENG":"We should be thanking– Huh?","TWN":"感謝的話應該由我們……嗯？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"하, 하늘에 비행형 침식체 다수 확인!","JPN":"そ、空に飛行型侵食体を多數確認！","ENG":"M-multiple flying C.O.s in the sky!","TWN":"確、確認天空有大量飛行型侵蝕體！"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"저 녀석들도 포격으로 격추할 수 있을까요?","JPN":"あいつらも砲撃で撃墜できるでしょうか？","ENG":"Can you shoot those down with artillery too?","TWN":"能用炮擊擊落那些傢伙嗎？"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"음~ 저만한 숫자를 전부 격추하기엔 무리겠는걸.","JPN":"うーん、あの数を全部落とすのは無理ね。","ENG":"Hm... Not all of them, not in those numbers.","TWN":"嗯～數量那麼多，要全部擊落有點勉強。"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"절반 정도는 어떻게 처리할 수 있으려나?","JPN":"半分ぐらいなら、なんとかできるかも？","ENG":"Maybe half, at best.","TWN":"大概能處理一半吧？"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"그, 그런…….","JPN":"そ、そんな……","ENG":"Th-that's...","TWN":"這、這怎麼……"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"시간이 없습니다!","JPN":"時間がありません！","ENG":"We don't have time!","TWN":"沒時間了！"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"빨리 도시에 연락해서 사람들을 다시 건물 안으로 피신시켜야……!","JPN":"早く都市に連絡し、人々を建物の中に移動させないと……！","ENG":"We need to alert the city and get everyone back inside buildings–!","TWN":"得趕快聯絡城市，讓大家再次撤回建築物內避難……！"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"너무 걱정하지 마, 후배님.","JPN":"心配しないでちょうだい。","ENG":"Don't worry too much, junior.","TWN":"別太擔心，後輩。"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"우리 애들이 저 녀석들을 전부 격추하지 못하더라도.","JPN":"うちの子どもたちが、あいつらを全部撃ち落とすことは難しいけど……","ENG":"Even if my guys can't shoot them all down,","TWN":"即使我們的人無法全部擊落那些傢伙，"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"하늘에선 아무도 막지 못하는 귀여운 중사님이 계시거든.","JPN":"空には、誰にも止められない可愛い軍曹がいるの。","ENG":"there's a certain cute sergeant nobody can stop in the air.","TWN":"空中可是有一位誰也擋不住的可愛中士呢。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"여긴 그리핀 1. 비행형 침식체 다수, 침묵 확인했습니다.","JPN":"こちらはグリフィン1。飛行型侵食体多數、沈黙を確認しました。","ENG":"This is Griffin 1. Multiple flyers confirmed, now silent.","TWN":"這裡是獅鷲1號。已確認多數飛行型侵蝕體沉默。"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"치, 침식체들이 전부 격추됐어?","JPN":"し、侵食体が全部撃墜された？","ENG":"Th-the C.O.s were all shot down?","TWN":"擊落所有侵、侵蝕體？"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};